try {
  const wd = sim.worldData
  if (!wd.__hel || wd.__hel.v !== 2) wd.__hel = { v: 2, sx: 150, sy: 120, phase: 0, lx: -1, ly: -1, glow: 0 }
  const S = wd.__hel
  const pdt = Math.min(dt, 0.05)
  const HORIZON = 336

  const md = wd.mouse_down, mx = wd.mouse_x, my = wd.mouse_y
  const aspw = 1
  // HOVER carries the sun — no press needed; the light lives at your cursor
  if (typeof mx === 'number' && (mx !== S.lx || my !== S.ly) && !(wd.__grove && wd.__grove.done)) {
    S.lx = mx; S.ly = my
    S.sx = Math.max(20, Math.min(492, mx))
    S.sy = Math.max(28, Math.min(HORIZON - 24, (my - 256) * aspw + 256))
  }
  // aging is ambient (full cycle ~70s); CLICKING makes time race (~7s)
  S.phase = (S.phase + pdt / (md ? 7 : 70)) % 1
  S.glow = md ? 1 : Math.max(0, S.glow - 1.5 * pdt)

  const moonness = 0.5 - 0.5 * Math.cos(2 * Math.PI * S.phase)

  // the secret: hover the moon's actual reflection on the lake
  const pyRaw = (typeof my === 'number') ? (my - 256) * aspw + 256 : -999
  const refY = 424 + (424 - S.sy) / 1.9
  const hov = moonness > 0.5 && refY < 512 && pyRaw > refY - 22 && pyRaw < refY + 26 ? 1 : 0
  S.gold = (S.gold || 0) + (hov - (S.gold || 0)) * Math.min(1, pdt * 5)
  if (typeof window !== 'undefined') {
    if (hov && !S.capd) { S.capd = true; window.dispatchEvent(new CustomEvent('cafe:caption', { detail: { text: 'the moon invites you · click', kind: 'hint' } })) }
    if (!hov) S.capd = false
    if (hov && md && !S.pmd) window.dispatchEvent(new CustomEvent('cafe:launch', { detail: 'SELENE' }))
  }
  // ── the six stones, the tree, the buds, and chapter III — all KEPT for the scene ──
  if (!wd.__grove || wd.__grove.v !== 2) {
    let sv = null
    try { sv = JSON.parse(localStorage.getItem('cc-helios-grove') || 'null') } catch (e) {}
    if (sv && sv.v === 1) sv = { v: 2, lit: sv.lit, started: sv.started, grow: sv.grow }
    const base = { v: 2, lit: [0, 0, 0, 0, 0, 0], started: 0, grow: 0,
                   buds: [0, 0, 0, 0, 0, 0, 0], kind: [0, 0, 0, 0, 0, 0, 0],
                   way: Math.floor(Math.random() * 7), ch3: 0, stars: [0, 0, 0, 0, 0, 0, 0], done: 0 }
    wd.__grove = (sv && sv.v === 2) ? Object.assign(base, sv) : base
    wd.__grove.v = 2
  }
  const G = wd.__grove
  if (!G.launch) G.launch = [0, 0, 0, 0, 0, 0, 0]
  const STONES = [[58, 372], [140, 394], [212, 408], [300, 408], [372, 394], [454, 372]]
  const BUDS_W = [[161, 228], [201, 178], [256, 158], [311, 176], [351, 226], [231, 203], [286, 210]]
  let allLit = true
  for (let i = 0; i < 6; i++) {
    if (G.lit[i] < 1) {
      const dd = Math.hypot(S.sx - STONES[i][0], S.sy - STONES[i][1])
      if (dd < 90) { G.lit[i] = Math.min(1, G.lit[i] + pdt / 3.5); if (G.lit[i] >= 1) G.dirty = 1 }
      if (G.lit[i] < 1) allLit = false
    }
  }
  G.cue = (allLit && !G.started) ? Math.min(1, (G.cue || 0) + pdt * 2) : Math.max(0, (G.cue || 0) - pdt * 2)
  if (allLit && !G.started && !G.hinted && typeof window !== 'undefined') {
    G.hinted = 1
    window.dispatchEvent(new CustomEvent('cafe:caption', { detail: { text: 'the six stones are lit \u00b7 click to wake the tree', kind: 'hint' } }))
  }
  const click = md && !S.pmd && !hov
  if (allLit && !G.started && click) {
    G.started = 1; G.dirty = 1
    wd.__play_sound = [
      { frequency: 110, duration: 0.8, volume: 0.35, type: 'sine' },
      { frequency: 440, duration: 0.5, volume: 0.25, type: 'triangle' },
    ]
  }
  if (G.started && G.grow < 1) { G.grow = Math.min(1, G.grow + pdt / 50); if (G.grow >= 1) G.dirty = 1 }

  // ── buds: each opens beautifully on a click; the correct one glows blue ──
  for (let i = 0; i < 7; i++) {
    if (G.kind[i] > 0 && G.buds[i] < 1) G.buds[i] = Math.min(1, G.buds[i] + pdt * 1.3)
  }
  if (click && G.grow >= 0.97 && !G.ch3 && typeof mx === 'number') {
    for (let i = 0; i < 7; i++) {
      if (G.kind[i] === 0 && Math.hypot(mx - BUDS_W[i][0], my - BUDS_W[i][1]) < 22) {
        G.kind[i] = (i === G.way) ? 2 : 1
        G.dirty = 1
        wd.__play_sound = { frequency: i === G.way ? 520 : 660 + i * 40, duration: 0.4, volume: 0.3, type: 'sine' }
      }
    }
  }
  // the blue bloom opens the night: veil to black, then CHAPTER III
  if (!G.ch3 && G.kind[G.way] === 2 && G.buds[G.way] >= 0.99 && !G.veiling) G.veiling = 1
  if (G.veiling === 1) {
    G.veil = Math.min(1, (G.veil || 0) + pdt * 0.8)
    if (G.veil >= 1) { G.ch3 = 1; G.ch3T = 0; G.veiling = 2; G.dirty = 1 }
  } else if (G.veiling === 2) {
    G.veil = Math.max(0, G.veil - pdt * 0.5)
    if (G.veil <= 0) G.veiling = 0
  }
  // ── chapter III: night holds; the tree bears fruit; seven stars reborn the sun ──
  if (G.ch3 && !G.done) {
    G.ch3T = (G.ch3T || 0) + pdt
    S.phase += (0.5 - S.phase) * Math.min(1, pdt * 0.5)
    if (!G.capN && typeof window !== 'undefined') {
      G.capN = 1
      window.dispatchEvent(new CustomEvent('cafe:caption', { detail: { text: 'CHAPTER III \u00b7 the tree bears fruit \u2014 pick each at its brightest', kind: 'hint' } }))
    }
    for (let i = 0; i < 7; i++) {
      if (G.launch[i] > 0 && G.stars[i] === 0) {
        G.launch[i] = Math.min(1, G.launch[i] + pdt * 0.8)
        if (G.launch[i] >= 1) { G.stars[i] = 1; G.launch[i] = 0; G.dirty = 1 }
      }
    }
    if (click && G.ch3T > 2 && typeof mx === 'number') {
      for (let i = 0; i < 7; i++) {
        if (G.stars[i] === 0 && G.launch[i] === 0 && Math.hypot(mx - BUDS_W[i][0], my - BUDS_W[i][1]) < 22) {
          const ripe = 0.5 + 0.5 * Math.sin(G.ch3T * 0.6 + i * 1.31)
          if (ripe > 0.7) { G.launch[i] = 0.001; wd.__play_sound = { frequency: 700 + i * 60, duration: 0.3, volume: 0.3, type: 'triangle' } }
        }
      }
    }
    if (G.stars.every(x => x === 1)) {
      G.done = 1; G.dirty = 1
      if (typeof window !== 'undefined') window.dispatchEvent(new CustomEvent('cafe:caption', { detail: { text: 'the sun is reborn', kind: 'hint' } }))
      wd.__play_sound = [{ frequency: 220, duration: 1.0, volume: 0.35, type: 'sine' }, { frequency: 880, duration: 0.8, volume: 0.2, type: 'sine' }]
    }
  }
  if (G.done) {
    G.dawn = Math.min(1, (G.dawn || 0) + pdt * 0.2)
    S.phase += (0.03 - S.phase) * Math.min(1, pdt * 0.6)
    S.sx += (256 - S.sx) * Math.min(1, pdt * 1.2)
    S.sy += (110 - S.sy) * Math.min(1, pdt * 1.2)
  }
  G.saveT = (G.saveT || 0) + pdt
  if (G.dirty || G.saveT > 5) {
    G.saveT = 0; G.dirty = 0
    try { localStorage.setItem('cc-helios-grove', JSON.stringify({ v: 2,
      lit: G.lit.map(x => Math.round(x * 100) / 100), started: G.started,
      grow: Math.round(G.grow * 100) / 100, buds: G.buds.map(x => Math.round(x * 100) / 100),
      kind: G.kind, way: G.way, ch3: G.ch3, stars: G.stars, done: G.done })) } catch (e) {}
  }
  S.pmd = md

  const fr = []
  for (let i = 0; i < 7; i++) {
    if (!G.ch3) fr.push(0)
    else if (G.stars[i] === 1) fr.push(4)
    else if (G.launch[i] > 0) fr.push(2 + G.launch[i])
    else if ((G.ch3T || 0) > 2 && !G.done) fr.push(Math.max(0.05, 0.5 + 0.5 * Math.sin((G.ch3T || 0) * 0.6 + i * 1.31)))
    else fr.push(0)
  }
  wd.gpuUniforms = [S.sx, S.sy, S.phase, S.glow, S.gold,
    G.lit[0], G.lit[1], G.lit[2], G.lit[3], G.lit[4], G.lit[5], G.grow, G.cue || 0,
    G.kind[0] === 2 ? G.buds[0] + 2 : G.buds[0],
    G.kind[1] === 2 ? G.buds[1] + 2 : G.buds[1],
    G.kind[2] === 2 ? G.buds[2] + 2 : G.buds[2],
    G.kind[3] === 2 ? G.buds[3] + 2 : G.buds[3],
    G.kind[4] === 2 ? G.buds[4] + 2 : G.buds[4],
    G.kind[5] === 2 ? G.buds[5] + 2 : G.buds[5],
    G.kind[6] === 2 ? G.buds[6] + 2 : G.buds[6],
    G.ch3 ? 1 : 0,
    fr[0], fr[1], fr[2], fr[3], fr[4], fr[5], fr[6],
    G.dawn || 0, G.veil || 0, G.way]
  wd.hud = [
    { id: 'hl_t', type: 'text', x: '14px', y: '12px', text: 'HELIOS' + (G.ch3 ? ' \u00b7 CHAPTER III' : '') + (G.done ? ' \u00b7 the sun is reborn' : '') + ' \u2014 ' + (moonness > 0.6 ? 'moonlight' : (moonness > 0.25 ? 'dusk' : 'daylight')), color: '#c9b370', fontSize: '13px' },
  ]

  const bg = sim.fields.get('hl_f')
  if (bg) { bg.transform.x = 256; bg.transform.y = 256; bg.transform.vx = 0; bg.transform.vy = 0 }
  const gv = sim.fields.get('hl_grove_f')
  if (gv) { gv.transform.x = 256; gv.transform.y = 256; gv.transform.vx = 0; gv.transform.vy = 0 }
} catch (e) { /* keep the sim alive */ }

visualTypes.wgsl:
const HL_HOR: f32 = 336.0;

fn hl_moonness(ph: f32) -> f32 { return 0.5 - 0.5 * cos(6.2831853 * ph); }

// sky + orb, callable so the lake can mirror it
fn hl_sky(p: vec2f, sun: vec2f, m: f32, t: f32, a: f32) -> vec3f {
  let up = clamp(1.0 - p.y / HL_HOR, 0.0, 1.0);
  // day palette → night palette
  let dayZen = vec3f(0.16, 0.34, 0.62);
  let dayHor = vec3f(0.95, 0.62, 0.32);
  let nightZen = vec3f(0.015, 0.020, 0.055);
  let nightHor = vec3f(0.05, 0.06, 0.13);
  var col = mix(mix(dayHor, dayZen, pow(up, 0.6)), mix(nightHor, nightZen, pow(up, 0.6)), m);

  // light breathes from wherever the orb is (screen-round despite the
  // vertical compression that fits the painting to wide viewports)
  let rel = vec2f(p.x - sun.x, (p.y - sun.y) / a);
  let d = length(rel);
  let warm = mix(vec3f(1.1, 0.7, 0.35), vec3f(0.55, 0.62, 0.80), m);
  col += warm * exp(-d * 0.012) * mix(0.5, 0.28, m);

  // the orb: gold sun ↔ silver moon with craters and a crescent bite
  let r = 26.0;
  if (d < r) {
    var oc = mix(vec3f(3.2, 2.4, 1.1), vec3f(1.6, 1.7, 1.9), m);
    // craters surface only as it becomes moon
    let cr = vnoise(rel * 0.22 + 7.0);
    oc *= 1.0 - m * 0.35 * smoothstep(0.45, 0.8, cr);
    // crescent: a dark disk slides across as moonness grows past half
    let bite = length(rel - vec2f(r * 0.85 * smoothstep(0.35, 1.0, m), -4.0));
    if (m > 0.35 && bite < r * 0.98) { oc *= 0.12; }
    col = oc;
  }
  col += warm * exp(-max(d - r, 0.0) * 0.05) * mix(0.9, 0.55, m);   // corona

  // stars belong to the moon
  if (m > 0.25) {
    let sp2 = p * 0.14;
    let cell = floor(sp2);
    let st = hash21(cell);
    if (st > 0.975 && p.y < HL_HOR - 10.0) {
      let d2 = length(fract(sp2) - 0.5);
      let tw = 0.5 + 0.5 * sin(t * 3.0 + st * 40.0);
      col += vec3f(0.9, 0.92, 1.0) * smoothstep(0.16, 0.02, d2) * tw * smoothstep(0.25, 0.6, m);
    }
  }
  return col;
}

fn hl_ridge(x: f32, seed: f32, amp: f32, base: f32) -> f32 {
  return base - amp * (fbm3(vec2f(x * 0.008 + seed, seed)) - 0.25);
}

fn visual_helios(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let asp = 1.0;   // contain-fit shows the whole painting
  let p = vec2f((uv.x + 1.0) * 256.0, (uv.y * asp + 1.0) * 256.0);
  let t = time;
  var sun = vec2f(uni(0), uni(1));
  if (sun.x < 1.0) { sun = vec2f(150.0, 120.0); }        // pre-hook default: morning
  let m = hl_moonness(uni(2));
  let gold = uni(4);

  var col: vec3f;
  let LAKE = 424.0;

  if (p.y < LAKE) {
    col = hl_sky(p, sun, m, t, asp);

    // three ridgelines, lit from wherever the orb hangs
    let warm = mix(vec3f(1.0, 0.75, 0.45), vec3f(0.5, 0.58, 0.75), m);
    let sunSide = clamp(1.0 - abs(p.x - sun.x) / 360.0, 0.0, 1.0);
    let r1 = hl_ridge(p.x, 3.0, 90.0, HL_HOR - 40.0);
    let r2 = hl_ridge(p.x, 11.0, 60.0, HL_HOR - 6.0);
    let r3 = hl_ridge(p.x, 27.0, 34.0, HL_HOR + 26.0);
    if (p.y > r3 && p.y < LAKE) {
      col = mix(vec3f(0.10, 0.16, 0.08), vec3f(0.012, 0.02, 0.03), m);
      col += warm * 0.35 * sunSide * smoothstep(r3 + 14.0, r3, p.y);  // lit brow
      col *= 0.9 + 0.2 * vnoise(p * 0.12);
    } else if (p.y > r2) {
      col = mix(vec3f(0.13, 0.20, 0.11), vec3f(0.02, 0.03, 0.05), m);
      col += warm * 0.30 * sunSide * smoothstep(r2 + 12.0, r2, p.y);
      col *= 0.9 + 0.2 * vnoise(p * 0.1 + 5.0);
    } else if (p.y > r1) {
      col = mix(vec3f(0.17, 0.25, 0.15), vec3f(0.03, 0.045, 0.07), m);
      col += warm * 0.28 * sunSide * smoothstep(r1 + 10.0, r1, p.y);
      col *= 0.9 + 0.2 * vnoise(p * 0.08 + 9.0);
    }

    // fireflies rise at night over the near meadow
    if (m > 0.5 && p.y > HL_HOR) {
      let fp2 = p * 0.06 + vec2f(0.0, t * 0.06);
      let fc = floor(fp2);
      let fh = hash21(fc + 31.0);
      if (fh > 0.955) {
        let fd = length(fract(fp2) - 0.5);
        let blink = pow(0.5 + 0.5 * sin(t * 2.5 + fh * 60.0), 3.0);
        col += vec3f(0.9, 1.4, 0.3) * smoothstep(0.10, 0.02, fd) * blink * (m - 0.5) * 2.4;
      }
    }
  } else {
    // the lake: the whole sky again, upside down and breathing
    let ry = LAKE - (p.y - LAKE) * 1.9;
    let wob = vnoise(vec2f(p.x * 0.05, p.y * 0.3 - t * 0.8)) - 0.5;
    var rp = vec2f(p.x + wob * 9.0, ry + wob * 5.0);
    col = hl_sky(rp, sun, m, t, asp) * mix(0.62, 0.5, m);
    col += vec3f(0.04, 0.05, 0.06) * (0.5 + wob);

    // moon-glitter: when the moon is out and its face lies on the lake,
    // the water sparkles along the reflection path
    let refY = LAKE + (LAKE - sun.y) / 1.9;
    let mglow = smoothstep(0.35, 0.75, m) * smoothstep(620.0, 500.0, refY);
    if (mglow > 0.01) {
      let depth = clamp((p.y - LAKE) / (512.0 - LAKE), 0.0, 1.0);
      let spread = 16.0 + 100.0 * depth;                 // the glade widens toward you
      let path = smoothstep(spread, spread * 0.2, abs(p.x - sun.x + wob * 14.0));
      // glint cells — little horizontal flecks, twinkling out of phase
      let gp = vec2f(p.x * 0.12, p.y * 0.3 - t * 0.55);
      let gh = hash21(floor(gp));
      let gd = length((fract(gp) - 0.5) * vec2f(0.9, 2.2));
      let flash = pow(0.5 + 0.5 * sin(t * (2.0 + gh * 6.0) + gh * 47.0), 6.0);
      let glint = smoothstep(0.45, 0.05, gd) * step(0.80, gh) * flash;
      col += vec3f(1.05, 1.12, 1.30) * glint * path * mglow * 2.8;   // the sparkle
      col += vec3f(0.35, 0.40, 0.55) * path * mglow * 0.20 * (0.6 + wob);  // silver sheen
      col += vec3f(1.30, 0.95, 0.40) * path * gold * 0.55 * (0.7 + wob);   // the invitation
    }
  }

  // hold feedback: a slow pulse ring while the orb is aging
  if (uni(3) > 0.01) {
    let ring = abs(length(vec2f(p.x - sun.x, (p.y - sun.y) / asp)) - (30.0 + fract(t * 0.8) * 26.0));
    col += vec3f(0.8, 0.8, 0.7) * uni(3) * smoothstep(3.0, 0.0, ring) * 0.5;
  }

  // the moon's reflection noticed you: the whole valley breathes gold
  if (gold > 0.01) {
    let breath = 0.5 + 0.5 * sin(t * 3.2);
    col += vec3f(1.05, 0.78, 0.28) * gold * (0.10 + 0.11 * breath) * (1.25 - 0.5 * length(uv));
  }

  col *= 1.0 - 0.35 * pow(length(uv), 3.0);
  return vec4f(col, 1.0);
}

fn visual_helios_grove(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = (uv + vec2f(1.0)) * 256.0;
  let t = time;
  let moon = 0.5 - 0.5 * cos(6.2831 * uni(2));
  let grow = uni(11);
  let cue = uni(12);
  let ch3 = clamp(uni(20), 0.0, 1.0);
  let dawn = clamp(uni(28), 0.0, 1.0);
  let veil = clamp(uni(29), 0.0, 1.0);
  let budsOn = smoothstep(0.94, 0.99, grow);
  let glowc = vec3f(2.2, 1.6, 0.5);
  var col = vec3f(0.0);
  var alpha = 0.0;

  {
    let sp = vec2f(58.0, 372.0);
    let lit = uni(5);
    let q = (p - sp) / 22.0;
    var d = length(q * vec2f(1.0, 1.3) - vec2f(0.0, -0.15)) - 0.85;
    d += (fbm3(q * 2.5 + vec2f(0.7, 0.0)) - 0.5) * 0.25;
    let m = smoothstep(0.06, -0.06, d);
    var rc = mix(vec3f(0.10, 0.11, 0.13), vec3f(0.30, 0.32, 0.36), clamp(0.5 - q.y * 0.5, 0.0, 1.0));
    rc *= 0.55 + 0.45 * (1.0 - moon);
    let pol = polar(q - vec2f(0.0, -0.1));
    let runes = step(0.55, sin(pol.y * 7.0 + 0.0)) * smoothstep(0.10, 0.03, abs(pol.x - 0.52));
    rc = mix(rc, glowc * (0.3 + lit), runes * (0.10 + 0.90 * lit));
    rc += glowc * lit * 0.5 * exp(-length(q) * 1.8);
    rc += glowc * cue * 0.5 * (0.5 + 0.5 * sin(t * 3.0 + 0.0)) * exp(-length(q) * 1.4);
    col = mix(col, rc, m);
    alpha = max(alpha, m);
  }
  {
    let sp = vec2f(140.0, 394.0);
    let lit = uni(6);
    let q = (p - sp) / 22.0;
    var d = length(q * vec2f(1.0, 1.3) - vec2f(0.0, -0.15)) - 0.85;
    d += (fbm3(q * 2.5 + vec2f(1.7, 0.0)) - 0.5) * 0.25;
    let m = smoothstep(0.06, -0.06, d);
    var rc = mix(vec3f(0.10, 0.11, 0.13), vec3f(0.30, 0.32, 0.36), clamp(0.5 - q.y * 0.5, 0.0, 1.0));
    rc *= 0.55 + 0.45 * (1.0 - moon);
    let pol = polar(q - vec2f(0.0, -0.1));
    let runes = step(0.55, sin(pol.y * 7.0 + 1.0)) * smoothstep(0.10, 0.03, abs(pol.x - 0.52));
    rc = mix(rc, glowc * (0.3 + lit), runes * (0.10 + 0.90 * lit));
    rc += glowc * lit * 0.5 * exp(-length(q) * 1.8);
    rc += glowc * cue * 0.5 * (0.5 + 0.5 * sin(t * 3.0 + 1.0)) * exp(-length(q) * 1.4);
    col = mix(col, rc, m);
    alpha = max(alpha, m);
  }
  {
    let sp = vec2f(212.0, 408.0);
    let lit = uni(7);
    let q = (p - sp) / 22.0;
    var d = length(q * vec2f(1.0, 1.3) - vec2f(0.0, -0.15)) - 0.85;
    d += (fbm3(q * 2.5 + vec2f(2.7, 0.0)) - 0.5) * 0.25;
    let m = smoothstep(0.06, -0.06, d);
    var rc = mix(vec3f(0.10, 0.11, 0.13), vec3f(0.30, 0.32, 0.36), clamp(0.5 - q.y * 0.5, 0.0, 1.0));
    rc *= 0.55 + 0.45 * (1.0 - moon);
    let pol = polar(q - vec2f(0.0, -0.1));
    let runes = step(0.55, sin(pol.y * 7.0 + 2.0)) * smoothstep(0.10, 0.03, abs(pol.x - 0.52));
    rc = mix(rc, glowc * (0.3 + lit), runes * (0.10 + 0.90 * lit));
