    // ── chapter III: the fruit / the launch / the star ──
    let f = uni(26);
    if (f > 0.01 && f <= 1.01) {
      let fd = length(lq) - 5.0;
      let fm2 = smoothstep(1.2, -1.2, fd);
      let ripe = smoothstep(0.55, 0.9, f);
      let fc2 = mix(vec3f(0.9, 0.55, 0.20), vec3f(3.0, 2.2, 0.8), ripe) * (0.75 + 0.25 * sin(t * 3.0 + 5.0));
      col = mix(col, fc2, fm2);
